import os, re, glob
from difflib import SequenceMatcher

files = sorted(glob.glob('/app/ocr/f_*.txt'))
def norm(l):
    return re.sub(r'\s+',' ', l.strip()).lower()

frames=[]
for f in files:
    lines=open(f, errors='ignore').read().split('\n')
    # drop first non-empty line (status bar)
    # find first index that's non-empty -> that's status bar
    out=[]
    dropped=False
    for l in lines:
        if not dropped and l.strip():
            dropped=True
            continue
        out.append(l.rstrip())
    # trim trailing empties
    while out and not out[-1].strip(): out.pop()
    while out and not out[0].strip(): out.pop(0)
    frames.append(out)

def eq(a,b):
    na,nb=norm(a),norm(b)
    if na==nb: return True
    if not na or not nb: return na==nb
    return SequenceMatcher(None,na,nb).ratio()>=0.8

buffer=[]
for F in frames:
    if not F: continue
    if not buffer:
        buffer.extend(F); continue
    best_o=0
    maxo=min(len(buffer),len(F))
    for o in range(maxo,0,-1):
        bt=buffer[-o:]; ft=F[:o]
        # match ratio
        m=sum(1 for x,y in zip(bt,ft) if eq(x,y))
        if m>=max(1,int(o*0.7)):
            best_o=o; break
    buffer.extend(F[best_o:])

open('/app/buffer.txt','w').write('\n'.join(buffer))
# extract commands
cmds=[]
for l in buffer:
    s=l.strip()
    if s.startswith('>'):
        c=s[1:].strip().rstrip('_').strip()
        if c: cmds.append(c)
print(len(buffer),'buffer lines',len(cmds),'cmds')
for c in cmds: print(repr(c))
